    @Test
    fun `Issue - Line starting with binary operator should not cause NullPointerException`() {
        val code =
            """
            package com.my.lint.rules

            import com.pinterest.ktlint.rule.engine.core.api.Rule
            import com.pinterest.ktlint.rule.engine.core.api.RuleId
            import org.jetbrains.kotlin.com.intellij.lang.ASTNode

            class BreakKtlintFormatRule : Rule(
                RuleId("my-ruleset:my-rule-id"),
                Rule.About(maintainer = "Me", repositoryUrl = "repositoryUrl", issueTrackerUrl = "issueTrackerUrl")
            ) {

                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
                ) {

                    if (node.text.contains("this")
                        || node.text.contains("that")
                    ) {
                        emit(node.startOffset, "My violation detail", false)
                    }
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            package com.my.lint.rules

            import com.pinterest.ktlint.rule.engine.core.api.Rule
            import com.pinterest.ktlint.rule.engine.core.api.RuleId
            import org.jetbrains.kotlin.com.intellij.lang.ASTNode

            class BreakKtlintFormatRule : Rule(
                RuleId("my-ruleset:my-rule-id"),
                Rule.About(maintainer = "Me", repositoryUrl = "repositoryUrl", issueTrackerUrl = "issueTrackerUrl")
            ) {

                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
                ) {

                    if (node.text.contains("this") ||
                        node.text.contains("that")
                    ) {
                        emit(node.startOffset, "My violation detail", false)
                    }
                }
            }
            """.trimIndent()
        // This test ensures that a line starting with "||" does not cause a NullPointerException
        // Previously this would crash with:
        // java.lang.NullPointerException: Cannot invoke "org.jetbrains.kotlin.com.intellij.lang.ASTNode.getElementType()" because the return value of "org.jetbrains.kotlin.com.intellij.lang.ASTNode.getFirstChildNode()" is null
        indentationRuleAssertThat(code)
            .hasLintViolation(19, 9, "Unexpected indentation (8) (should be 12)")
            .isFormattedAs(formattedCode)
    }"}

